package unit.information;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.NullAndEmptySource;
import org.junit.jupiter.params.provider.ValueSource;
import persistence.model.Information;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

public class DescriptionTest {

    // ------------------------------ Positive values ------------------------------

    @ParameterizedTest
    @DisplayName("Description should accept valid lengths.")
    @ValueSource(strings = {
            "AAAAAAAAAA",
            "AAAAAAAAAAA",
            "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA",
            "",
            "",
            "Line one\nLine two",
            "Maintenance starts at 18:00."
    })
    void descriptionShouldAcceptValidLengths(String description) {
        // When
        Information subject = new Information();
        subject.setDescription(description);

        // Then
        assertThat(subject.getDescription()).isEqualTo(description).isNotBlank().hasSizeBetween(10, 500);
        assertThat(subject.getDescription() != null
                && !subject.getDescription().isBlank()
                && subject.getDescription().length() >= 10
                && subject.getDescription().length() <= 500).isTrue();
    }

    // ------------------------------ Negative values ------------------------------

    @ParameterizedTest
    @DisplayName("Description should reject invalid lengths.")
    @ValueSource(strings = {
            "",
            "A",
            "AA",
            "AAAAA",
            "AAAAAAAA",
            "AAAAAAAAA",
            "",
            "",
            ""
    })
    void descriptionShouldRejectInvalidLengths(String description) {
        // Given
        Information subject = new Information();

        // Then
        assertThatThrownBy(() -> subject.setDescription(description))
                .isInstanceOf(IllegalArgumentException.class);
    }

    // ------------------------------ Edge cases ------------------------------

    @ParameterizedTest
    @DisplayName("Description should reject null, empty, and blank values.")
    @NullAndEmptySource
    @ValueSource(strings = {
            " "
    })
    void descriptionShouldRejectNullEmptyAndBlankValues(String description) {
        // Given
        Information subject = new Information();

        // Then
        assertThatThrownBy(() -> subject.setDescription(description))
                .isInstanceOf(IllegalArgumentException.class);
    }

}
